import{_ as a,o as t,c as n,a6 as i}from"./chunks/framework.CG5ubMb2.js";const p=JSON.parse('{"title":"Fakes API","description":"Create and configure fake functions with returns, throws, yields, and async behavior.","frontmatter":{"title":"Fakes API","description":"Create and configure fake functions with returns, throws, yields, and async behavior."},"headers":[],"relativePath":"concepts/fakes/api/index.md","filePath":"concepts/fakes/api/index.md"}'),r={name:"concepts/fakes/api/index.md"};function s(o,e,c,f,l,d){return t(),n("div",null,[...e[0]||(e[0]=[i('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /concepts/fakes/api.md for this page in Markdown format</div><h1 id="fakes-api" tabindex="-1">Fakes API <a class="header-anchor" href="#fakes-api" aria-label="Permalink to “Fakes API”">​</a></h1><p>There are three ways you can create fakes:</p><ol><li>Create an empty fake</li><li>Wrap an existing function</li><li>Use a fake factory</li></ol><h2 id="create-an-empty-fake" tabindex="-1">Create an empty fake <a class="header-anchor" href="#create-an-empty-fake" aria-label="Permalink to “Create an empty fake”">​</a></h2><p>A basic fake can be created with no behavior. It saves call information.</p><h2 id="wrap-an-existing-function" tabindex="-1">Wrap an existing function <a class="header-anchor" href="#wrap-an-existing-function" aria-label="Permalink to “Wrap an existing function”">​</a></h2><p>You can use <code>sinon.fake</code> to wrap an existing function. This can be used for either observing the <a href="https://en.wikipedia.org/wiki/System_under_test" target="_blank" rel="noreferrer">system under test</a>, or for creating complex fakes with behaviour. You can pass an arbitrarily complex function to <code>sinon.fake</code> to create custom behavior for a test.</p><h2 id="use-a-fake-factory" tabindex="-1">Use a fake factory <a class="header-anchor" href="#use-a-fake-factory" aria-label="Permalink to “Use a fake factory”">​</a></h2><p>The API has a few factories to quickly create fakes with behavior:</p><ul><li><a href="./rejects">fake.rejects</a></li><li><a href="./resolves">fake.resolves</a></li><li><a href="./returns">fake.returns</a></li><li><a href="./throws">fake.throws</a></li><li><a href="./yields">fake.yields</a></li><li><a href="./yields-async">fake.yieldsAsync</a></li></ul><h2 id="plugging-in-the-fake" tabindex="-1">Plugging in the fake <a class="header-anchor" href="#plugging-in-the-fake" aria-label="Permalink to “Plugging in the fake”">​</a></h2><p>Unlike <a href="/concepts/spies/"><code>sinon.spy</code></a> and <a href="/concepts/stubs/"><code>sinon.stub</code></a> methods, the <code>sinon.fake</code> API knows only how to <em>create</em> fakes, and doesn&#39;t concern itself with plugging them into the system under test.</p><p>To plug the fakes into the system under test, you can use the <a href="/concepts/sandboxes/api/replace"><code>sinon.replace*</code></a> methods.</p>',14)])])}const k=a(r,[["render",s]]);export{p as __pageData,k as default};
